#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=110,Mod=998244353;
inline void DN(int &x){x>=Mod?x-=Mod:0;}inline void UP(int &x){x<0?x+=Mod:0;}
int dp[N][N],l[N],r[N],n,All=1,P[N],p,ifac[N],fac[N];
inline int qpow(int a,int b=Mod-2){int r(1);for(;b;b>>=1,a=1ll*a*a%Mod)if(b&1)r=1ll*r*a%Mod;return r;}
inline int bnd(int x){int l(1),r(p),m;while(l<=r)P[m=(l+r)>>1]<=x?l=m+1:r=m-1;return l-1;}
inline int C(int n,int m){int res=ifac[m];while(m--)res=1ll*res*(n--)%Mod;return res;}
int main()
{
	n=read();rep(1,n,i)l[i]=read(),r[i]=read()+1,All=1ll*All*(r[i]-l[i])%Mod;
	rep(1,n,i)P[++p]=l[i],P[++p]=r[i];sort(P+1,P+p+1);p=unique(P+1,P+p+1)-P-1;
	rep(1,n,i)l[i]=bnd(l[i]),r[i]=bnd(r[i]);dp[0][p]=1;l[0]=p;r[0]=p+1;
	fac[0]=ifac[0]=1;rep(1,n+3,i)fac[i]=1ll*fac[i-1]*i%Mod,ifac[i]=qpow(fac[i]);
//	rep(1,p,i)printf("%d ",P[i]);puts("");
//	rep(1,n,i)printf("%d :: %d %d\n",i,l[i],r[i]);
	rep(1,n,i)
	{
		rep(l[i],r[i]-1,j)
		{
			drep(i-1,0,ls)
			{
				
				int tmp=0;rep(max(j+1,l[ls]),r[ls]-1,k)DN(tmp+=dp[ls][k]);
				dp[i][j]=(1ll*tmp*C(P[j+1]-P[j]+i-ls-1,i-ls)+dp[i][j])%Mod;
				if(r[ls]<=j||l[ls]>j)break;
			}
		}
	}
//	rep(0,n,i){rep(1,p,j)printf("%d ",dp[i][j]);puts("");}
	int ans=0;rep(l[n],r[n]-1,i)DN(ans+=dp[n][i]);
	printf("%lld\n",1ll*ans*qpow(All)%Mod);
}
